 2257: 	} else if (*lblk < le32_to_cpu(ex->ee_block)) {
 2258: 		len = le32_to_cpu(ex->ee_block) - *lblk;
 2259: 	} else if (*lblk >= le32_to_cpu(ex->ee_block)
 2260: 			+ ext4_ext_get_actual_len(ex)) {
