  601: 		if (IS_ERR(oi->of_binfo[i].ob_bh)) {
  602: 			ret = PTR_ERR(oi->of_binfo[i].ob_bh);
  603: 			goto out_free;
  604: 		}
  605: 		if (!oi->of_binfo[i].ob_bh) {
