  618: 			ret = -EIO;
  619: 			goto out_free;
  620: 		}
  621: 		bdata = (__le32 *)(oi->of_binfo[i].ob_bh->b_data);
  622: 		free = 0;
  623: 		for (j = 0; j < inodes_per_ob; j++)
  624: 			if (bdata[j] == 0)
